import{_ as a,o,c as i,ai as t}from"./chunks/framework.CsYGeNYI.js";const f=JSON.parse('{"title":"Platforms","description":"","frontmatter":{"summary":"Platform support overview (Gateway + companion apps)","read_when":["Looking for OS support or install paths","Deciding where to run the Gateway"],"title":"Platforms"},"headers":[],"relativePath":"platforms/index.md","filePath":"platforms/index.md","lastUpdated":1771906665000}'),l={name:"platforms/index.md"};function s(r,e,n,d,c,p){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="platforms" tabindex="-1"><a class="header-anchor" href="#platforms">#</a> Platforms</h1><p>OpenSoul core is written in TypeScript. <strong>Node is the recommended runtime</strong>. Bun is not recommended for the Gateway (WhatsApp/Telegram bugs).</p><p>Companion apps exist for macOS (menu bar app), Windows (native WPF app), and mobile nodes (iOS/Android). Linux companion app is planned; the Gateway is fully supported on all platforms.</p><h2 id="choose-your-os" tabindex="-1"><a class="header-anchor" href="#choose-your-os">#</a> Choose your OS</h2><ul><li>macOS: <a href="/docs/platforms/macos">macOS</a></li><li>iOS: <a href="/docs/platforms/ios">iOS</a></li><li>Android: <a href="/docs/platforms/android">Android</a></li><li>Windows: <a href="/docs/platforms/windows">Windows</a></li><li>Linux: <a href="/docs/platforms/linux">Linux</a></li></ul><h2 id="vps-hosting" tabindex="-1"><a class="header-anchor" href="#vps-hosting">#</a> VPS &amp; hosting</h2><ul><li>VPS hub: <a href="/docs/vps">VPS hosting</a></li><li>Fly.io: <a href="/docs/install/fly">Fly.io</a></li><li>Hetzner (Docker): <a href="/docs/install/hetzner">Hetzner</a></li><li>GCP (Compute Engine): <a href="/docs/install/gcp">GCP</a></li><li>exe.dev (VM + HTTPS proxy): <a href="/docs/install/exe-dev">exe.dev</a></li></ul><h2 id="common-links" tabindex="-1"><a class="header-anchor" href="#common-links">#</a> Common links</h2><ul><li>Install guide: <a href="/docs/start/getting-started">Getting Started</a></li><li>Gateway runbook: <a href="/docs/gateway/index">Gateway</a></li><li>Gateway configuration: <a href="/docs/gateway/configuration">Configuration</a></li><li>Service status: <code>opensoul gateway status</code></li></ul><h2 id="gateway-service-install-cli" tabindex="-1"><a class="header-anchor" href="#gateway-service-install-cli">#</a> Gateway service install (CLI)</h2><p>Use one of these (all supported):</p><ul><li>Wizard (recommended): <code>opensoul onboard --install-daemon</code></li><li>Direct: <code>opensoul gateway install</code></li><li>Configure flow: <code>opensoul configure</code> → select <strong>Gateway service</strong></li><li>Repair/migrate: <code>opensoul doctor</code> (offers to install or fix the service)</li></ul><p>The service target depends on OS:</p><ul><li>macOS: LaunchAgent (<code>ai.opensoul.gateway</code> or <code>ai.opensoul.&lt;profile&gt;</code>; legacy <code>com.opensoul.*</code>)</li><li>Linux/WSL2: systemd user service (<code>opensoul-gateway[-&lt;profile&gt;].service</code>)</li></ul>',14)])])}const u=a(l,[["render",s]]);export{f as __pageData,u as default};
